def min_rollout_cost(n, costs):
    full = (1 << n) - 1
    dp = [float('inf')] * (1 << n)
    dp[0] = 0
    for mask in range(1, full + 1):
        sub = mask
        while sub > 0:
            dp[mask] = min(dp[mask], dp[mask ^ sub] + costs[sub])
            sub = (sub - 1) & mask
    return dp[full]
